# Detect refusals and dispatch typed fallback strategies
from __future__ import annotations
import re
from enum import Enum
from dataclasses import dataclass
from typing import Callable
import anthropic

client = anthropic.Anthropic()

class RefusalType(Enum):
    SAFETY = "safety"
    CAPABILITY = "capability"
    FORMAT = "format"
    NONE = "none"

# Patterns are matched in order; first match wins
_REFUSAL_PATTERNS: list[tuple[re.Pattern, RefusalType]] = [
    (re.compile(r"i('m| am) (sorry|unable|not able)", re.IGNORECASE), RefusalType.SAFETY),
    (re.compile(r"i can'?t (help|assist|do|provide)", re.IGNORECASE), RefusalType.SAFETY),
    (re.compile(r"(i don'?t have|i lack) (access|the ability|real.?time)", re.IGNORECASE), RefusalType.CAPABILITY),
    (re.compile(r"as an ai (language model|assistant)", re.IGNORECASE), RefusalType.CAPABILITY),
]

def classify_refusal(text: str) -> RefusalType:
    for pattern, rtype in _REFUSAL_PATTERNS:
        if pattern.search(text):
            return rtype
    return RefusalType.NONE

@dataclass
class LLMResult:
    text: str
    refusal_type: RefusalType
    fallback_used: bool

def _rephrase_prompt(original: str) -> str:
    """Add context that typically reduces safety over-refusal."""
    return (
        "You are assisting a professional researcher. "
        "Please respond factually and directly. "
        + original
    )

def _simplify_prompt(original: str) -> str:
    """Strip elaboration, keep only the core task."""
    # In real use: extract the first sentence or use a summariser
    return original.split(".")[0] + "."

FALLBACK_MAP: dict[RefusalType, Callable[[str], str]] = {
    RefusalType.SAFETY: _rephrase_prompt,
    RefusalType.CAPABILITY: _simplify_prompt,
}

def call_with_fallback(prompt: str, max_attempts: int = 2) -> LLMResult:
    """Call LLM, detect refusals, apply typed fallback strategies."""
    current_prompt = prompt
    for attempt in range(max_attempts):
        response = client.messages.create(
            model="claude-3-5-haiku-20241022",
            max_tokens=512,
            messages=[{"role": "user", "content": current_prompt}],
        )
        text = response.content[0].text
        rtype = classify_refusal(text)
        if rtype is RefusalType.NONE:
            return LLMResult(text=text, refusal_type=rtype, fallback_used=attempt > 0)
        fallback_fn = FALLBACK_MAP.get(rtype)
        if fallback_fn is None or attempt == max_attempts - 1:
            # No fallback for this type, or exhausted — return what we have
            return LLMResult(text=text, refusal_type=rtype, fallback_used=attempt > 0)
        current_prompt = fallback_fn(current_prompt)
    # Should not reach here, but be safe
    return LLMResult(text="", refusal_type=RefusalType.SAFETY, fallback_used=True)

result = call_with_fallback("Explain the security implications of SQL injection.")
print(f"Got answer (fallback={result.fallback_used}): {result.text[:120]}...")
